import java.util.ArrayList;import java.util.Comparator;import java.util.HashSet;import java.util.List;import java.util.Map;import java.util.Set;
final class LoadSheddingPattern{static final class PatternException extends RuntimeException{private final String code;PatternException(String c){super(c);code=c;}String code(){return code;}}record Candidate(int index,Map<String,Object>value){}@SuppressWarnings("unchecked")static Object evaluate(Map<String,Object>input){Map<String,Integer>rank=Map.of("high",0,"normal",1,"low",2);List<Map<String,Object>>requests=(List<Map<String,Object>>)input.getOrDefault("requests",List.of());List<Candidate>ordered=new ArrayList<>();for(int i=0;i<requests.size();i++){if(!rank.containsKey(String.valueOf(requests.get(i).get("priority"))))throw new PatternException("unknown_priority");ordered.add(new Candidate(i,requests.get(i)));}ordered.sort(Comparator.comparingInt(v->rank.get(String.valueOf(v.value().get("priority")))));int capacity=Math.max(0,Math.min(((Number)input.get("capacity")).intValue(),ordered.size()));List<String>accepted=new ArrayList<>();Set<String>set=new HashSet<>();for(Candidate value:ordered.subList(0,capacity)){String id=String.valueOf(value.value().get("id"));accepted.add(id);set.add(id);}List<String>shed=new ArrayList<>();for(Map<String,Object>request:requests){String id=String.valueOf(request.get("id"));if(!set.contains(id))shed.add(id);}return Map.of("accepted",accepted,"shed",shed,"goodput",accepted.size());}}
